     [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
     public async Task<string> GetForecast(
         [Description("Latitude of the location")] double latitude,
         [Description("Longitude of the location")] double longitude,
         [Description("Number of forecast days (1-7)")] int days = 3,
         CancellationToken cancellationToken = default)
     {
         days = Math.Clamp(days, 1, 7);
         logger.LogInformation("Fetching {Days}-day forecast for ({Lat}, {Lon})", days, latitude, longitude);

         var url = $"{BaseUrl}/forecast?latitude={latitude}&longitude={longitude}"
                 + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

         var response = await httpClient.GetStringAsync(url, cancellationToken);
         var doc = JsonDocument.Parse(response);
         var daily = doc.RootElement.GetProperty("daily");

         var dates = daily.GetProperty("time").EnumerateArray().Select(e => e.GetString()).ToList();
         var highs = daily.GetProperty("temperature_2m_max").EnumerateArray().Select(e => e.GetDouble()).ToList();
         var lows = daily.GetProperty("temperature_2m_min").EnumerateArray().Select(e => e.GetDouble()).ToList();

         var lines = dates.Select((date, i) => $"{date}: High {highs[i]}°C, Low {lows[i]}°C");
         return string.Join("\n", lines);
     }
 }
